;; Chez SMP GC uses active_threads count (NOT S_nthreads) for rendezvous.
;;
;; Key C macros in types.h:
;;   deactivate_thread(tc) — sets ACTIVE(tc)=0, decrements active_threads.
;;     When active_threads reaches 0 and collect_request_pending, signals GC.
;;   reactivate_thread(tc) — sets ACTIVE(tc)=1, increments active_threads.
;;
;; Chez automatically deactivates threads during:
;;   - sleep (make-time based)
;;   - condition-wait (mutex + condition variable)
;;   - mutex-acquire (when blocked)
;;
;; Chez does NOT deactivate during foreign calls (c-lambda, foreign-procedure).
;; If a thread blocks in a foreign call, it stays ACTIVE and GC waits for it.
;;
;; Public C API (in scheme.h):
;;   EXPORT int Sactivate_thread(void);
;;   EXPORT void Sdeactivate_thread(void);
;;
;; For Scheme-level code, use condition-wait or sleep around blocking
;; operations. For C shims doing blocking I/O, call Sdeactivate_thread()
;; before the blocking call and Sactivate_thread() after.
;;
;; CRITICAL: If your event loop calls blocking FFI on the primordial thread,
;; it freezes the entire app — use background threads for blocking work
;; and post results back via a UI queue.

/* SSH chacha20-poly1305@openssh.com uses raw Poly1305 MAC,
 * NOT OpenSSL's EVP_chacha20_poly1305() which implements RFC 8439 AEAD.
 *
 * RFC 8439 AEAD pads AAD and ciphertext to 16-byte boundaries and
 * appends 8-byte lengths before computing the Poly1305 tag.
 * OpenSSH just runs raw Poly1305 over (enc_length || enc_payload).
 *
 * Correct implementation:
 *   1. Encrypt length (4 bytes) with K1/ChaCha20, counter=0
 *   2. Generate Poly1305 key: ChaCha20(K2, counter=0) → first 32 bytes
 *   3. Encrypt payload with K2/ChaCha20, counter=1
 *   4. MAC = raw Poly1305(enc_length || enc_payload, poly_key)
 *
 * Use EVP_chacha20() (plain) + EVP_MAC("POLY1305") separately.
 * Do NOT use EVP_chacha20_poly1305() for SSH packets.
 */

/* OpenSSL ChaCha20 IV format: counter(4 LE) || nonce(12) */
static void build_chacha_iv(uint64_t seqno, uint32_t counter, uint8_t *iv16) {
    iv16[0] = counter & 0xFF;
    iv16[1] = (counter >> 8) & 0xFF;
    iv16[2] = (counter >> 16) & 0xFF;
    iv16[3] = (counter >> 24) & 0xFF;
    iv16[4] = 0; iv16[5] = 0; iv16[6] = 0; iv16[7] = 0;
    iv16[8]  = (seqno >> 56) & 0xFF;
    iv16[9]  = (seqno >> 48) & 0xFF;
    iv16[10] = (seqno >> 40) & 0xFF;
    iv16[11] = (seqno >> 32) & 0xFF;
    iv16[12] = (seqno >> 24) & 0xFF;
    iv16[13] = (seqno >> 16) & 0xFF;
    iv16[14] = (seqno >> 8)  & 0xFF;
    iv16[15] = seqno & 0xFF;
}

/* Raw Poly1305 MAC via OpenSSL EVP_MAC */
static int poly1305_mac(const uint8_t *key32,
    const uint8_t *data, int datalen, uint8_t *tag16) {
    EVP_MAC *mac = EVP_MAC_fetch(NULL, "POLY1305", NULL);
    EVP_MAC_CTX *mctx = EVP_MAC_CTX_new(mac);
    EVP_MAC_free(mac);
    size_t taglen = 16;
    EVP_MAC_init(mctx, key32, 32, NULL);
    EVP_MAC_update(mctx, data, datalen);
    EVP_MAC_final(mctx, tag16, &taglen, 16);
    EVP_MAC_CTX_free(mctx);
    return 0;
}

;; In C, after openpty() + fork():
int ffi_pty_fork_exec(...) {
    int master, slave;
    openpty(&master, &slave, NULL, NULL, NULL);
    pid_t child = fork();
    if (child > 0) {
        close(slave);
        /* CRITICAL: Set non-blocking so event loop doesn't stall */
        fcntl(master, F_SETFL, fcntl(master, F_GETFL) | O_NONBLOCK);
        return child;
    }
    /* child: setsid, TIOCSCTTY, dup2 slave→0/1/2, exec */
}

;; In Scheme, the non-blocking read wrapper:
;; Returns: >0 (bytes read), 0 (EAGAIN, nothing available), -1 (EOF/error)
int ffi_bv_read_nonblock(int fd, unsigned char *buf, int offset, int max_len) {
    ssize_t n;
    do { n = read(fd, buf + offset, max_len); } while (n < 0 && errno == EINTR);
    if (n < 0) {
        if (errno == EAGAIN || errno == EWOULDBLOCK) return 0;
        return -1;  /* real error (EIO when slave closes) */
    }
    if (n == 0) return -1;  /* EOF */
    return (int)n;
}

