/* In the C main of a static Chez binary, call putenv("JEMACS_STATIC=1")
 * BEFORE Sscheme_init. This tells Jerboa stdlib modules that use the
 * JEMACS_STATIC check to skip their load-shared-object calls.
 *
 * Without this, modules like (std net io) call (load-shared-object #f)
 * at startup to load libc symbols — which crashes in a musl static binary
 * since musl's load-shared-object throws "not supported".
 */

#include "scheme.h"
#include <stdlib.h>  /* for putenv */

int main(int argc, const char *argv[]) {
    /* Must be set BEFORE Sscheme_init — Scheme module initializers
     * run during Sbuild_heap and check this variable. */
    putenv("JEMACS_STATIC=1");

    Sscheme_init(NULL);
    Sregister_boot_file_bytes("petite", petite_boot_data, petite_boot_size);
    Sregister_boot_file_bytes("scheme", scheme_boot_data, scheme_boot_size);
    Sbuild_heap(NULL, custom_init);  /* custom_init registers Sforeign_symbol */

    const char *prog = write_program_tmpfile();
    Sscheme_program(prog, argc, argv);
    unlink(prog);
    Sscheme_deinit();
    return 0;
}

